def compute_score() -> tuple[str, float]:
    # Use VLM to verify on slide 4 whether both target phrases appear and are bolded
    target_phrases = ["85th and 94th percentiles", "95th percentile"]
    slide_4_image = None
    for s in modified_ppt_screenshots:
        try:
            if getattr(s, 'slide_number', None) == 4:
                slide_4_image = s.image_path
                break
        except Exception:
            continue
    if not slide_4_image:
        return ("Slide 4 screenshot not found.", 0.0)

    prompt = (
        "Look at slide 4. Focus on these two exact phrases:\n"
        "1) '85th and 94th percentiles'\n"
        "2) '95th percentile'\n"
        "Are BOTH phrases visually bold (strong weight)?\n"
        "Respond YES if both are bold, PARTIAL if only is bold, and NONE if neither is bold or missing. Include a brief justification."
    )
    try:
        response = vlm_call(images=[slide_4_image], prompt=prompt, temperature=0.1)
        resp = str(response).strip().upper()
        if 'YES' in resp:
            return (response, 1.0)
        elif 'PARTIAL' in resp:
            return (response, 0.5)
        elif 'NO' in resp:
            return (response, 0.0)
        else:
            return (f"Unclear VLM response: {response}", 0.0)
    except Exception as e:
        return (f"Error during VLM check: {str(e)}", 0.0)

def compute_score() -> tuple[str, float]:
    # Use VLM to compare original vs modified slide 4 and detect extraneous bolding beyond the target phrases
    target_phrases = ["85th and 94th percentiles", "95th percentile"]
    img_orig = None
    img_mod = None
    for s in original_ppt_screenshots:
        try:
            if getattr(s, 'slide_number', None) == 4:
                img_orig = s.image_path
                break
        except Exception:
            continue
    for s in modified_ppt_screenshots:
        try:
            if getattr(s, 'slide_number', None) == 4:
                img_mod = s.image_path
                break
        except Exception:
            continue
    if not img_mod:
        return ("Modified slide 4 screenshot not found.", 0.0)
    if not img_orig:
        return ("Original slide 4 screenshot not found.", 1.0)  # Can't penalize without baseline

    allowed = ", ".join([f'"{p}"' for p in target_phrases])
    prompt = (
        "Compare these two images of slide 4: first is original, second is modified.\n"
        f"Ignore bolding of the allowed phrases: {allowed}.\n"
        "Has any OTHER text been newly made bold in the modified slide compared to the original?\n"
        "Respond YES if there is extraneous bolding (beyond the allowed phrases), otherwise NO. Include a brief justification."
    )
    try:
        response = vlm_call(images=[img_orig, img_mod], prompt=prompt, temperature=0.1)
        resp = str(response).strip().lower()
        if 'yes' in resp:
            return (response, 0.0)
        elif 'no' in resp:
            return (response, 1.0)
        else:
            return (f"Unclear VLM response: {response}", 0.0)
    except Exception as e:
        return (f"Error during VLM comparison: {str(e)}", 0.0)
